import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.y1bVONfd.js";const p=JSON.parse('{"title":"Interface Tour","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/interface-tour.md","filePath":"getting-started/interface-tour.md"}'),o={name:"getting-started/interface-tour.md"};function i(l,t,s,d,g,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="interface-tour" tabindex="-1">Interface Tour <a class="header-anchor" href="#interface-tour" aria-label="Permalink to &quot;Interface Tour&quot;">​</a></h1><h2 id="toolbar-top" tabindex="-1">Toolbar (Top) <a class="header-anchor" href="#toolbar-top" aria-label="Permalink to &quot;Toolbar (Top)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Button</th><th>Action</th></tr></thead><tbody><tr><td>🐾 WebBeagle Builder</td><td>Home logo</td></tr><tr><td>Project dropdown</td><td>Switch between projects</td></tr><tr><td>Page dropdown</td><td>Switch between pages</td></tr><tr><td>+ Page</td><td>Add a new page</td></tr><tr><td>📂 Projects</td><td>Manage projects modal</td></tr><tr><td>🎨 Theme</td><td>Edit theme CSS</td></tr><tr><td>🤖 AI</td><td>AI generation panel</td></tr><tr><td>🎬 Animate</td><td>Open animation panel (manual toggle)</td></tr><tr><td>🧪 Anim Test</td><td>Load animation test page</td></tr><tr><td>📦 Save as Block</td><td>Save current content as reusable block</td></tr><tr><td>↩️ / ↪️</td><td>Undo / Redo</td></tr><tr><td>💾 Save</td><td>Save to server</td></tr><tr><td>🚀 Publish</td><td>Publish project</td></tr></tbody></table><h2 id="left-panel-—-blocks" tabindex="-1">Left Panel — Blocks <a class="header-anchor" href="#left-panel-—-blocks" aria-label="Permalink to &quot;Left Panel — Blocks&quot;">​</a></h2><p>The blocks panel shows available components. Drag any block onto the canvas.</p><p><strong>Categories:</strong></p><ul><li><strong>Layout</strong> — Sections, containers, grids</li><li><strong>Typography</strong> — Headers, paragraphs, badges</li><li><strong>Content</strong> — Cards, testimonials, stats</li><li><strong>Forms</strong> — Inputs, textareas, buttons, selects, labels</li></ul><h2 id="right-panel-—-style-manager" tabindex="-1">Right Panel — Style Manager <a class="header-anchor" href="#right-panel-—-style-manager" aria-label="Permalink to &quot;Right Panel — Style Manager&quot;">​</a></h2><p>Select any element on the canvas to view style controls:</p><ul><li><strong>Typography</strong> — Font, size, weight, color, alignment</li><li><strong>Dimension</strong> — Width, height, margin, padding</li><li><strong>Background</strong> — Color, gradient, image</li><li><strong>Border</strong> — Width, style, color, radius</li><li><strong>Position</strong> — Static, relative, absolute, fixed</li></ul><h2 id="right-panel-—-animation-🎬-animate" tabindex="-1">Right Panel — Animation (🎬 Animate) <a class="header-anchor" href="#right-panel-—-animation-🎬-animate" aria-label="Permalink to &quot;Right Panel — Animation (🎬 Animate)&quot;">​</a></h2><p><strong>Click the 🎬 Animate button to open.</strong> This panel controls scroll-triggered animations.</p><ul><li><strong>ON/OFF toggle</strong> — Enable/disable animation on selected element</li><li><strong>Preset grid</strong> — fade-up, fade-in, slide-left, slide-right, zoom-in</li><li><strong>Stagger Delay</strong> — Time between child animations (ms)</li><li><strong>Duration</strong> — Animation length (ms)</li><li><strong>Initial Opacity</strong> — Starting opacity (0 = invisible, 1 = fully visible)</li><li><strong>Trigger</strong> — On Scroll or On Page Load</li><li><strong>✨ Stagger All Children</strong> — Auto-tag children for staggered animation</li></ul><h2 id="canvas" tabindex="-1">Canvas <a class="header-anchor" href="#canvas" aria-label="Permalink to &quot;Canvas&quot;">​</a></h2><p>The canvas is a GrapesJS iframe. You can:</p><ul><li>Click to select elements</li><li>Double-click text to edit inline</li><li>Drag blocks from the left panel</li><li>Right-click for context menu (copy, delete, etc.)</li><li>Use the device switcher (Desktop / Tablet / Mobile)</li></ul>',16)])])}const m=e(o,[["render",i]]);export{p as __pageData,m as default};
